Then, create the JavaScript file `sketch.js`:

```javascript
let grid;
let button;
let cellSize = 50;

function setup() {
  let canvas = createCanvas(7 * cellSize, 8 * cellSize);
  canvas.parent("sketch-holder");
  grid = new Array(7).fill("").map(() => new Array(8).fill(false));

  button = createButton("Random Position");
  button.parent("sketch-holder");
  button.mousePressed(selectRandomPosition);
}

function draw() {
  background(255);
  drawGrid();
}

function drawGrid() {
  for (let i = 0; i < grid.length; i++) {
    for (let j = 0; j < grid[i].length; j++) {
      if (grid[i][j]) {
        fill(0, 255, 0);
      } else {
        fill(255);
      }
      stroke(0);
      rect(i * cellSize, j * cellSize, cellSize, cellSize);
    }
  }
}

function selectRandomPosition() {
  let col = floor(random(grid.length));
  let row = floor(random(grid[0].length));
  grid[col][row] = !grid[col][row];
}
```

This program creates a 7x8 grid, and it displays a button named "Random Position." When you click the button, it will select a random position from the grid and change the color of the selected cell.

