```javascript
let button;
let cellSize = 50;
const selectedCells = [];

function setup() {
  let canvas = createCanvas(7 * cellSize, 8 * cellSize);
  canvas.parent("sketch-holder");

  button = createButton("Random Position");
  button.parent("sketch-holder");
  button.mousePressed(selectRandomPosition);
}

function draw() {
  background(255);
  drawGrid();
  drawSelectedCells();
}

function drawGrid() {
  for (let i = 0; i < 7; i++) {
    for (let j = 0; j < 8; j++) {
      stroke(0);
      noFill();
      rect(i * cellSize, j * cellSize, cellSize, cellSize);
    }
  }
}

function drawSelectedCells() {
  stroke(255, 0, 0);
  for (const cell of selectedCells) {
    let x1 = cell.col * cellSize;
    let y1 = cell.row * cellSize;
    line(x1, y1, x1 + cellSize, y1 + cellSize);
    line(x1, y1 + cellSize, x1 + cellSize, y1);
  }
}

function selectRandomPosition() {
  if (selectedCells.length >= 7 * 8) {
    alert("All cells have been selected.");
    return;
  }

  let col, row;
  do {
    col = floor(random(7));
    row = floor(random(8));
  } while (isSelected(col, row));

  selectedCells.push({ col, row });
}

function isSelected(col, row) {
  return selectedCells.some(cell => cell.col === col && cell.row === row);
}
```

The `selectedCells` array has been introduced to store the previous cells' positions. In the `selectRandomPosition` function, the code continues to choose random cell positions until it finds one that has not been previously selected. The `drawSelectedCells` function then draws all 'X's on the cells stored in the `selectedCells` array.

Once all cells have been selected, an alert will notify you that all cells have been chosen.

